CREATE TABLE users (
  user_id      INT PRIMARY KEY,
  username     VARCHAR(30),
  email        VARCHAR(80),
  password_hash VARCHAR(100),  -- SENSITIVE: never expose
  salary       DECIMAL(10,2),  -- SENSITIVE: HR only
  role         VARCHAR(20),
  created_at   TIMESTAMP DEFAULT NOW()
);

INSERT INTO users VALUES
  (1, 'alice', 'alice@co.com', '$2b$10$abc123hashedpassword1', 95000, 'admin', NOW()),
  (2, 'bob',   'bob@co.com',   '$2b$10$abc123hashedpassword2', 65000, 'user',  NOW()),
  (3, 'carol', 'carol@co.com', '$2b$10$abc123hashedpassword3', 88000, 'user',  NOW());

-- Public view: safe columns for general app use
CREATE VIEW public_users AS
  SELECT user_id, username, email, role, created_at
  FROM users;

-- HR view: hides password but shows salary
CREATE VIEW hr_users AS
  SELECT user_id, username, email, salary, role
  FROM users;

-- Query both views
SELECT * FROM public_users;
SELECT * FROM hr_users;

-- In production: GRANT SELECT ON public_users TO app_role;
-- GRANT SELECT ON hr_users TO hr_manager_role;

CREATE TABLE customers (id INT PRIMARY KEY, name VARCHAR(50), country VARCHAR(30));
CREATE TABLE orders    (id INT PRIMARY KEY, customer_id INT, order_date DATE);
CREATE TABLE order_items (id INT PRIMARY KEY, order_id INT, product VARCHAR(60), quantity INT, price DECIMAL(8,2));

INSERT INTO customers VALUES (1,'Alice','USA'),(2,'Bob','UK'),(3,'Carol','USA');
INSERT INTO orders VALUES (101,1,'2026-01-05'),(102,1,'2026-01-10'),(103,2,'2026-01-12'),(104,3,'2026-01-15');
INSERT INTO order_items VALUES
  (1,101,'Laptop',1,999.99),(2,101,'Mouse',2,19.99),
  (3,102,'Keyboard',1,59.99),(4,103,'Monitor',2,299.99),
  (5,104,'Headphones',1,79.99),(6,104,'Mouse',3,19.99);

-- Without view: this complex query must be repeated everywhere
-- WITH view: define it once
CREATE VIEW order_summary AS
  SELECT
    o.id AS order_id,
    c.name AS customer,
    c.country,
    o.order_date,
    COUNT(oi.id)              AS line_count,
    SUM(oi.quantity * oi.price) AS order_total
  FROM orders o
  JOIN customers c ON o.customer_id = c.id
  JOIN order_items oi ON o.id = oi.order_id
  GROUP BY o.id, c.name, c.country, o.order_date;

-- Now application code can use simple queries
SELECT * FROM order_summary ORDER BY order_total DESC;
SELECT customer, SUM(order_total) AS lifetime_value FROM order_summary GROUP BY customer;
SELECT * FROM order_summary WHERE country = 'USA';

CREATE TABLE products (
  id INT PRIMARY KEY, name VARCHAR(80), category VARCHAR(40),
  price DECIMAL(8,2), active BOOLEAN DEFAULT TRUE
);

INSERT INTO products VALUES
  (1,'Laptop','Electronics',999.99,TRUE),
  (2,'Mouse','Electronics',19.99,TRUE),
  (3,'Desk','Furniture',250.00,TRUE),
  (4,'Old Model','Electronics',79.99,FALSE);

-- Create initial view
CREATE VIEW active_products AS
  SELECT id, name, category, price FROM products WHERE active = TRUE;

SELECT * FROM active_products;

-- Modify the view: add calculated column (discounted price)
-- CREATE OR REPLACE replaces without needing DROP first
CREATE OR REPLACE VIEW active_products AS
  SELECT
    id,
    name,
    category,
    price,
    ROUND(price * 0.9, 2) AS discounted_price  -- 10% off
  FROM products
  WHERE active = TRUE;

SELECT * FROM active_products;

-- Drop the view when no longer needed
DROP VIEW IF EXISTS active_products;

-- Confirm it's gone
SELECT viewname FROM pg_views WHERE schemaname = 'public' AND viewname = 'active_products';
